const actionData = $json.respostaIA.actionData;

// Validação Básica
if (!actionData) throw new Error ('Objeto actionData Inválido');
if (!actionData.nome_cliente) throw new Error ('Nome do cliente obrigatório');
if (!actionData.telefone_cliente) throw new Error ('Telefone do cliente obrigatório');
if (!actionData.placa_veiculo) throw new Error ('Placa obrigatória');

// --- SANITIZAÇÃO ---

// 1. Telefone: Remove tudo que não é número
// Se não tiver 55 no começo e tiver tamanho de celular BR (11 digitos), adiciona 55
let phone = actionData.telefone_cliente.replace(/[^0-9]/g, '');
if (phone.length === 11 || phone.length === 10) phone = '55' + phone;
actionData.telefone_cliente = phone;

// 2. Placa: Maiúsculo e sem traços
actionData.placa_veiculo = actionData.placa_veiculo.replace(/[^a-zA-Z0-9]/g, '').toUpperCase();

// 3. Textos Gerais
actionData.nome_cliente = actionData.nome_cliente.trim();
actionData.modelo_veiculo = (actionData.modelo_veiculo || '').toUpperCase().trim();
actionData.marca_veiculo = (actionData.marca_veiculo || '').toUpperCase().trim();

// Atualiza o JSON
$input.item.json.respostaIA.actionData = actionData;

return $input.item;

