const inputItem = $input.item.json;

// CENÁRIO 1: Fluxo de Erro (Vindo do Process Error)
if (inputItem.error) {
    return $input.item;
}

// CENÁRIO 2: Fluxo de Sucesso
const originalItem = $('Validate & Sanitize').item.json;

// Tenta injetar o ID da OS criada (se existir)
try {
    const osNode = $('Criar OS').last();
    if (osNode && osNode.json && osNode.json.id) {
        originalItem.os_criada_id = osNode.json.id;

        if (originalItem.respostaIA && originalItem.respostaIA.actionData) {
             originalItem.respostaIA.actionData.os_id_gerado = osNode.json.id;
        }
    }
} catch (e) {}

return { json: originalItem };

// 1. Recupera o contexto original seguro
const originalContext = $('Validate & Sanitize').item.json;

// 2. Recupera o erro
const errorDetails = $input.item.json; 

// 3. Cria resposta de erro
const errorResponse = {
    ...originalContext, 
    error: true,
    errorDetails: errorDetails
};

// 4. Sobrescreve mensagem para a IA
if (errorResponse.respostaIA) {
  if (errorDetails.errorPhone) {
    errorResponse.respostaIA.userMessage = errorDetails.errorPhone;
  } else {
    errorResponse.respostaIA.userMessage = "⚠️ *Erro Técnico*\n\nOcorreu uma falha ao registrar a OS de Balcão. Verifique os dados e tente novamente.";
  }

    errorResponse.respostaIA.nextState = errorResponse.respostaIA.currentState;
    errorResponse.respostaIA.actionDataContext = {};
}

return { json: errorResponse };
